INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  'df20aaec-2fc5-4e7e-b6cb-5d0a1768aac9', 'energy_vitality', 1,
  'Energy Reset Foundations', 'Day 1 - Energy Reset Foundations', '', 10,
  '[{"type":"intro","dayNumber":1,"dayTitle":"Energy Reset Foundations","goal":"Begin restoring your body''s natural rhythm controlled by the\nCircadian Rhythm.","estimatedMinutes":10},{"type":"lesson","title":"Today’s focus","paragraphs":["Begin restoring your body''s natural rhythm controlled by the","Circadian Rhythm."],"highlight":"Begin restoring your body''s natural rhythm controlled by the"},{"type":"action_step","stepNumber":1,"title":"Morning Hydration","duration":"10 minutes","instructions":["Drink 500 ml water within 10 minutes of waking."],"whyThisWorks":"Hydration supports blood flow and oxygen delivery, which helps the body create steadier energy."},{"type":"action_step","stepNumber":2,"title":"Morning Sunlight","duration":"10–15 minutes","instructions":["Get 10–15 minutes of morning sunlight."],"whyThisWorks":"Morning light anchors the circadian rhythm so daytime energy rises more naturally and nighttime sleep becomes easier.","proTip":"Weak daylight is still useful. Stay out a little longer if the morning is cloudy."},{"type":"exercise_routine","title":"Movement Reset","totalDuration":"10 minutes","exercises":[{"name":"With Walking for 20 Mins","instructions":["Perform the movement with steady breathing and controlled form."]},{"name":"Neck Rolls","instructions":["Move with controlled form and steady breathing."],"duration":"1 min"},{"name":"Shoulder Rotations","instructions":["Move with controlled form and steady breathing."],"duration":"1 min"},{"name":"Arm Swings","instructions":["Move with controlled form and steady breathing."],"duration":"1 min"},{"name":"Bodyweight Squats","instructions":["Move with controlled form and steady breathing."],"duration":"2 min"},{"name":"Light Walk","instructions":["Move with controlled form and steady breathing."],"duration":"5 min"}]},{"type":"action_step","stepNumber":4,"title":"Screen Wind-down","duration":"30 minutes","instructions":["No screens 30 minutes before sleep."],"whyThisWorks":"Reducing screen exposure lowers stimulation and blue light, which helps the nervous system shift into recovery mode."},{"type":"mindfulness_exercise","title":"Breathing Reset","duration":"5 minutes","steps":["Do 5 minutes deep breathing before bed.","Let each exhale lengthen slightly so the body can settle before sleep."],"timerSeconds":300,"completionMessage":"Finish when the breath feels slower and the body feels less alert."},{"type":"action_step","stepNumber":6,"title":"Consistent Sleep Time","duration":"7 hours","instructions":["Sleep at a fixed time (minimum 7 hours).","-- Optional (Hidden) Under each step you can add a small button:","\"Why this works\" If they tap it, then show the explanation.","Most users won''t read it daily, but it builds trust and credibility."],"whyThisWorks":"A fixed sleep window improves overnight repair and helps the body expect energy at the same time each day."},{"type":"close","message":"Day 1 is complete.","secondaryMessage":"Begin restoring your body''s natural rhythm controlled by the\nCircadian Rhythm."}]'::jsonb
)
