  '[{"type":"intro","dayNumber":2,"dayTitle":"Sleep Rhythm Stabilization","goal":"Strengthen your body''s natural sleep–wake cycle controlled by the\nCircadian Rhythm.\n\n---","estimatedMinutes":10},{"type":"lesson","title":"Today’s focus","paragraphs":["Strengthen your body''s natural sleep–wake cycle controlled by the","Circadian Rhythm.","--"],"highlight":"Strengthen your body''s natural sleep–wake cycle controlled by the"},{"type":"action_step","stepNumber":1,"title":"Morning Hydration","duration":"10 minutes","instructions":["Drink 500 ml water within 10 minutes of waking."],"whyThisWorks":"Hydration supports blood flow and oxygen delivery, which helps the body create steadier energy."},{"type":"action_step","stepNumber":2,"title":"Morning Sunlight","duration":"10–15 minutes","instructions":["Get 10–15 minutes of morning sunlight."],"whyThisWorks":"Morning light anchors the circadian rhythm so daytime energy rises more naturally and nighttime sleep becomes easier.","proTip":"Weak daylight is still useful. Stay out a little longer if the morning is cloudy."},{"type":"exercise_routine","title":"Movement Reset","totalDuration":"12 minutes","exercises":[{"name":"With Walking for 20 Mins","instructions":["Perform the movement with steady breathing and controlled form."]},{"name":"Neck Rolls","instructions":["Move with controlled form and steady breathing."],"duration":"1 min"},{"name":"Shoulder Rotations","instructions":["Move with controlled form and steady breathing."],"duration":"1 min"},{"name":"Arm Swings","instructions":["Move with controlled form and steady breathing."],"duration":"1 min"},{"name":"Bodyweight Squats","instructions":["Move with controlled form and steady breathing."],"duration":"2 min"},{"name":"Light Walk","instructions":["Move with controlled form and steady breathing."],"duration":"7 min"}]},{"type":"action_step","stepNumber":4,"title":"Energy Practice","instructions":["Drink 2–2.5 liters of water throughout the day."],"whyThisWorks":"Hydration supports blood flow and oxygen delivery, which helps the body create steadier energy."},{"type":"action_step","stepNumber":5,"title":"Screen Wind-down","duration":"45 minutes","instructions":["No screens 45 minutes before sleep."],"whyThisWorks":"Reducing screen exposure lowers stimulation and blue light, which helps the nervous system shift into recovery mode."},{"type":"mindfulness_exercise","title":"Breathing Reset","duration":"5 minutes","steps":["Do 5 minutes deep breathing before bed.","Let each exhale lengthen slightly so the body can settle before sleep."],"timerSeconds":300,"completionMessage":"Finish when the breath feels slower and the body feels less alert."},{"type":"action_step","stepNumber":7,"title":"Consistent Sleep Time","duration":"7 hours","instructions":["Sleep at the same time as Day 1 (minimum 7 hours)."],"whyThisWorks":"A fixed sleep window improves overnight repair and helps the body expect energy at the same time each day."},{"type":"close","message":"Day 2 is complete.","secondaryMessage":"Strengthen your body''s natural sleep–wake cycle controlled by the\nCircadian Rhythm.\n\n---"}]'::jsonb
